import{_ as e,c as t,o as p,ae as r}from"./chunks/framework.BvcDoAct.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ja-jp/RockInOnJapan_BF/0.md","filePath":"ja-jp/RockInOnJapan_BF/0.md"}'),n={name:"ja-jp/RockInOnJapan_BF/0.md"};function o(_,a,s,c,i,S){return p(),t("div",null,[...a[0]||(a[0]=[r('<h2 id="進化し続けた日々の根底に、刻まれたそれぞれの信念ーー" tabindex="-1">進化し続けた日々の根底に、刻まれたそれぞれの信念ーー <a class="header-anchor" href="#進化し続けた日々の根底に、刻まれたそれぞれの信念ーー" aria-label="Permalink to &quot;進化し続けた日々の根底に、刻まれたそれぞれの信念ーー&quot;">​</a></h2><h2 id="be-firstを追いかけてきたjapanが贈る、過去から未来へのロングパス・インタビュー" tabindex="-1">BE:FIRSTを追いかけてきたJAPANが贈る、過去から未来へのロングパス・インタビュー <a class="header-anchor" href="#be-firstを追いかけてきたjapanが贈る、過去から未来へのロングパス・インタビュー" aria-label="Permalink to &quot;BE:FIRSTを追いかけてきたJAPANが贈る、過去から未来へのロングパス・インタビュー&quot;">​</a></h2><p>2021年、オーディションプロジェクト「THE FIRST」から誕生したBE:FIRSTは、11月3日、メジャーデビュー4周年を迎えた。その直前の10月29日にリリースされたのは、グループ初のベストアルバム『BE:ST』。4年でベストアルバムーー普通のアーティストなら少し早いようにも感じるが、トラックリストに並ぶ30以上の楽曲を見つめると納得する。ここに刻まれた多彩で多様な楽曲たちは、彼らの濃密な日々の足跡であり、進化の証だ。</p><p>4年前、事務所の社長兼プロデューサーのSKY-HIによる導きのもとに歩き出したBE:FIRSTは今、健全な自由さと貪欲な好奇心を手に、自らの足で次々とステップを駆け上がっている。ドームツアーからワールドツアー、スタジアム公演へと続くライブ規模の拡大はその証左だ。何よりその裏には、メンバー自身が楽曲制作に積極的に関わり、「今、必要な音」をその手で手繰り寄せて作ってきた道のりがある。《最高が何なのか証明しよう》とは1stアルバム「BE:1」のリード曲“Scream&quot;の一節だが、その宣言通り、彼らは常に自ら「最高」を更新し証明しながらここまで歩んできたのだ。</p><p>『BE:ST』のタイミングでBE:FIRSTの特集を作るにあたって考えたのは、その輝かしい歴史の裏でメンバー一人ひとりが何を考えていたのかを解き明かしたい、ということだった。</p><p>最強の進化集団・BE:FIRSTとして生きていくうえで、彼らはどう変わり、どんなふうに変わらないできたのかーー実はJAPANでは、「BE:1」リリース後の2022年秋から約半年をかけて、メンバーへのソロ取材連載を敢行している。今回の別冊特集では、当時それぞれが語っていた言葉をピックアップしながら、彼らの根底に流れる信念に今一度触れるインタビューにトライした(なお、各インタビューページには、3年前の記事に掲載した懐かしの写真も再掲しているので、その変化にも注目してほしい)。</p><p>なぜBE:FIRSTはBE:FIRSTなのか。なぜ最高を証明し続けられるのか。</p><p>その真髄に触れられる、オンリーワンの特集になったと思う。 <br><br></p><p>(安田季那子)</p><p>インタビュー=小川智宏 撮影=大野隼男</p>',10)])])}const l=e(n,[["render",o]]);export{d as __pageData,l as default};
